using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;

namespace ContosoUniversity.Tests
{
    public static class TestHelper
    {
        public static SchoolContext CreateInMemoryContext()
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(Guid.NewGuid().ToString())
                .Options;
            var context = new SchoolContext(options);
            context.Database.EnsureCreated();
            return context;
        }

        public static void SeedStudents(SchoolContext context)
        {
            context.Students.AddRange(
                new Student { FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = DateTime.Parse("2020-09-01") },
                new Student { FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = DateTime.Parse("2021-09-01") },
                new Student { FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = DateTime.Parse("2022-09-01") }
            );
            context.SaveChanges();
        }

        public static Department SeedDepartmentWithInstructor(SchoolContext context)
        {
            var instructor = new Instructor
            {
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = DateTime.Parse("1995-03-11")
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            var department = new Department
            {
                Name = "Engineering",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = instructor.ID
            };
            context.Departments.Add(department);
            context.SaveChanges();

            return department;
        }

        public static Course SeedCourseWithDepartment(SchoolContext context)
        {
            var department = SeedDepartmentWithInstructor(context);
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = department.DepartmentID
            };
            context.Courses.Add(course);
            context.SaveChanges();
            return course;
        }
    }
}

