using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut;

        [TestInitialize]
        public void Setup()
        {
            _sut = new NotificationService();
            // Drain any leftover notifications from the static queue
            while (_sut.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut.Dispose();
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_EnqueuesCorrectNotification()
        {
            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("Admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
            Assert.IsTrue(notification.Message.Contains("John Doe"));
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesEntityIdInMessage()
        {
            _sut.SendNotification("Course", "42", EntityOperation.UPDATE);

            var notification = _sut.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains("ID: 42"));
        }

        [TestMethod]
        public void SendNotification_WithNullUserName_DefaultsToSystem()
        {
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();

            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "created")]
        [DataRow(EntityOperation.UPDATE, "updated")]
        [DataRow(EntityOperation.DELETE, "deleted")]
        public void SendNotification_GeneratesCorrectMessageVerb(EntityOperation operation, string expectedVerb)
        {
            _sut.SendNotification("Student", "1", "Test Student", operation);

            var notification = _sut.ReceiveNotification();

            Assert.IsTrue(notification.Message.Contains(expectedVerb),
                $"Expected message to contain '{expectedVerb}', got '{notification.Message}'");
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_IncludesNameInMessage()
        {
            _sut.SendNotification("Department", "5", "Engineering", EntityOperation.CREATE);

            var notification = _sut.ReceiveNotification();

            Assert.IsTrue(notification.Message.Contains("Engineering"));
            Assert.IsTrue(notification.Message.Contains("Department"));
        }

        [TestMethod]
        public void ReceiveNotification_WhenQueueEmpty_ReturnsNull()
        {
            var result = _sut.ReceiveNotification();

            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_ReturnsInFIFOOrder()
        {
            _sut.SendNotification("A", "1", EntityOperation.CREATE);
            _sut.SendNotification("B", "2", EntityOperation.UPDATE);

            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();

            Assert.AreEqual("A", first.EntityType);
            Assert.AreEqual("B", second.EntityType);
        }

        [TestMethod]
        public void ReceiveNotification_RemovesItemFromQueue()
        {
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);

            var first = _sut.ReceiveNotification();
            var second = _sut.ReceiveNotification();

            Assert.IsNotNull(first);
            Assert.IsNull(second);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            _sut.MarkAsRead(999);
        }

        [TestMethod]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            var service = new NotificationService();
            service.Dispose();
            service.Dispose();
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAt()
        {
            var before = System.DateTime.Now;
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = System.DateTime.Now;

            var notification = _sut.ReceiveNotification();

            Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_SetsPropertiesCorrectly()
        {
            var items = new List<string> { "a", "b", "c" };

            var sut = new PaginatedList<string>(items, 10, 2, 3);

            Assert.AreEqual(2, sut.PageIndex);
            Assert.AreEqual(4, sut.TotalPages); // ceil(10/3) = 4
            Assert.AreEqual(3, sut.Count);
        }

        [TestMethod]
        [DataRow(1, false, DisplayName = "First page has no previous")]
        [DataRow(2, true, DisplayName = "Second page has previous")]
        [DataRow(3, true, DisplayName = "Third page has previous")]
        public void HasPreviousPage_ReturnsCorrectValue(int pageIndex, bool expected)
        {
            var sut = new PaginatedList<int>(new List<int>(), 30, pageIndex, 10);

            Assert.AreEqual(expected, sut.HasPreviousPage);
        }

        [TestMethod]
        [DataRow(1, 3, true, DisplayName = "First of 3 pages has next")]
        [DataRow(3, 3, false, DisplayName = "Last page has no next")]
        [DataRow(2, 3, true, DisplayName = "Middle page has next")]
        public void HasNextPage_ReturnsCorrectValue(int pageIndex, int totalPages, bool expected)
        {
            // totalPages * 10 items with page size 10 gives totalPages pages
            var sut = new PaginatedList<int>(new List<int>(), totalPages * 10, pageIndex, 10);

            Assert.AreEqual(expected, sut.HasNextPage);
        }

        [TestMethod]
        [DataRow(10, 3, 4, DisplayName = "10 items / 3 per page = 4 pages")]
        [DataRow(9, 3, 3, DisplayName = "9 items / 3 per page = 3 pages")]
        [DataRow(1, 10, 1, DisplayName = "1 item / 10 per page = 1 page")]
        [DataRow(0, 10, 0, DisplayName = "0 items = 0 pages")]
        public void TotalPages_CalculatesCorrectly(int totalCount, int pageSize, int expectedPages)
        {
            var sut = new PaginatedList<int>(new List<int>(), totalCount, 1, pageSize);

            Assert.AreEqual(expectedPages, sut.TotalPages);
        }

        [TestMethod]
        public void Create_ReturnsCorrectPageItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.AreEqual(2, result.PageIndex);
            Assert.AreEqual(3, result.TotalPages);
            Assert.AreEqual(10, result.Count);
            Assert.AreEqual(11, result.First());
            Assert.AreEqual(20, result.Last());
        }

        [TestMethod]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            var source = Enumerable.Range(1, 15).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.AreEqual(1, result.PageIndex);
            Assert.AreEqual(10, result.Count);
            Assert.IsTrue(result.HasNextPage);
            Assert.IsFalse(result.HasPreviousPage);
        }

        [TestMethod]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 15).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.AreEqual(2, result.PageIndex);
            Assert.AreEqual(5, result.Count);
            Assert.IsFalse(result.HasNextPage);
            Assert.IsTrue(result.HasPreviousPage);
        }

        [TestMethod]
        public void Create_SinglePage_HasNoNavigation()
        {
            var source = Enumerable.Range(1, 5).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.AreEqual(1, result.TotalPages);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void Constructor_AddsAllItems()
        {
            var items = new List<int> { 10, 20, 30 };

            var sut = new PaginatedList<int>(items, 3, 1, 3);

            CollectionAssert.AreEqual(items, sut);
        }
    }
}

