using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class HomeControllerTests
    {
        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            using var context = TestHelper.CreateInMemoryContext();
            var controller = new HomeController(context);

            var result = controller.Index();

            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }

        [TestMethod]
        public void About_ReturnsViewWithEnrollmentDateGroups()
        {
            using var context = TestHelper.CreateInMemoryContext();
            var date1 = DateTime.Parse("2020-09-01");
            var date2 = DateTime.Parse("2021-09-01");
            context.Students.AddRange(
                new Student { FirstMidName = "A", LastName = "A", EnrollmentDate = date1 },
                new Student { FirstMidName = "B", LastName = "B", EnrollmentDate = date1 },
                new Student { FirstMidName = "C", LastName = "C", EnrollmentDate = date2 }
            );
            context.SaveChanges();
            var controller = new HomeController(context);

            var result = controller.About() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Count);
        }

        [TestMethod]
        public void About_EmptyDatabase_ReturnsEmptyList()
        {
            using var context = TestHelper.CreateInMemoryContext();
            var controller = new HomeController(context);

            var result = controller.About() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            Assert.AreEqual(0, model.Count);
        }

        [TestMethod]
        public void About_GroupsStudentsByEnrollmentDate()
        {
            using var context = TestHelper.CreateInMemoryContext();
            var date = DateTime.Parse("2020-09-01");
            context.Students.AddRange(
                new Student { FirstMidName = "A", LastName = "A", EnrollmentDate = date },
                new Student { FirstMidName = "B", LastName = "B", EnrollmentDate = date }
            );
            context.SaveChanges();
            var controller = new HomeController(context);

            var result = controller.About() as ViewResult;

            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual(2, model[0].StudentCount);
        }

        [TestMethod]
        public void Contact_ReturnsViewWithMessage()
        {
            using var context = TestHelper.CreateInMemoryContext();
            var controller = new HomeController(context);

            var result = controller.Contact() as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Your contact page.", controller.ViewBag.Message);
        }

        [TestMethod]
        public void Error_ReturnsViewResult()
        {
            using var context = TestHelper.CreateInMemoryContext();
            var controller = new HomeController(context);

            var result = controller.Error();

            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }

        [TestMethod]
        public void Unauthorized_ReturnsViewWithPermissionMessage()
        {
            using var context = TestHelper.CreateInMemoryContext();
            var controller = new HomeController(context);

            var result = controller.Unauthorized() as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("You don't have permission to access this resource.", controller.ViewBag.Message);
        }
    }
}

