using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Moq;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Net;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class CoursesControllerTests
    {
        private CoursesController CreateController(out SchoolContext context)
        {
            context = TestHelper.CreateInMemoryContext();
            var env = new Mock<IWebHostEnvironment>();
            env.Setup(e => e.WebRootPath).Returns(Path.GetTempPath());
            env.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
            var logger = Mock.Of<ILogger<CoursesController>>();
            return new CoursesController(context, env.Object, logger);
        }

        private Course SeedCourse(SchoolContext context)
        {
            return TestHelper.SeedCourseWithDepartment(context);
        }

        private static IFormFile CreateMockFile(string fileName, long size)
        {
            var mock = new Mock<IFormFile>();
            mock.Setup(f => f.FileName).Returns(fileName);
            mock.Setup(f => f.Length).Returns(size);
            mock.Setup(f => f.CopyTo(It.IsAny<Stream>()));
            return mock.Object;
        }

        // --- Index ---

        [TestMethod]
        public void Index_ReturnsViewWithCourses()
        {
            var controller = CreateController(out var context);
            SeedCourse(context);

            var result = controller.Index() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<Course>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
        }

        [TestMethod]
        public void Index_EmptyDatabase_ReturnsEmptyList()
        {
            var controller = CreateController(out _);

            var result = controller.Index() as ViewResult;

            var model = result.Model as List<Course>;
            Assert.AreEqual(0, model.Count);
        }

        // --- Details ---

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithCourse()
        {
            var controller = CreateController(out var context);
            var course = SeedCourse(context);

            var result = controller.Details(course.CourseID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Course;
            Assert.AreEqual("Chemistry", model.Title);
        }

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var controller = CreateController(out _);

            var result = controller.Details(null) as StatusCodeResult;

            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        // --- Create GET ---

        [TestMethod]
        public void Create_Get_ReturnsViewWithDepartmentDropdown()
        {
            var controller = CreateController(out var context);
            TestHelper.SeedDepartmentWithInstructor(context);

            var result = controller.Create() as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsNotNull(controller.ViewBag.DepartmentID);
        }

        [TestMethod]
        public void Create_Get_ReturnsNewCourseModel()
        {
            var controller = CreateController(out _);

            var result = controller.Create() as ViewResult;

            Assert.IsInstanceOfType(result.Model, typeof(Course));
        }

        // --- Create POST ---

        [TestMethod]
        public void Create_Post_ValidCourse_RedirectsToIndex()
        {
            var controller = CreateController(out var context);
            var dept = TestHelper.SeedDepartmentWithInstructor(context);
            var course = new Course { CourseID = 2000, Title = "New Course", Credits = 3, DepartmentID = dept.DepartmentID };

            var result = controller.Create(course, null) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(1, context.Courses.Count());
        }

        [TestMethod]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            var controller = CreateController(out var context);
            TestHelper.SeedDepartmentWithInstructor(context);
            controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 2000, DepartmentID = 1 };

            var result = controller.Create(course, null) as ViewResult;

            Assert.IsNotNull(result);
        }

        [TestMethod]
        [DataRow(".exe", DisplayName = "Rejects .exe")]
        [DataRow(".txt", DisplayName = "Rejects .txt")]
        [DataRow(".pdf", DisplayName = "Rejects .pdf")]
        public void Create_Post_InvalidFileExtension_ReturnsError(string extension)
        {
            var controller = CreateController(out var context);
            var dept = TestHelper.SeedDepartmentWithInstructor(context);
            var course = new Course { CourseID = 3000, Title = "Test", Credits = 3, DepartmentID = dept.DepartmentID };
            var file = CreateMockFile($"test{extension}", 100);

            var result = controller.Create(course, file) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [TestMethod]
        public void Create_Post_FileTooLarge_ReturnsError()
        {
            var controller = CreateController(out var context);
            var dept = TestHelper.SeedDepartmentWithInstructor(context);
            var course = new Course { CourseID = 3000, Title = "Test", Credits = 3, DepartmentID = dept.DepartmentID };
            var file = CreateMockFile("test.jpg", 6 * 1024 * 1024); // 6MB > 5MB limit

            var result = controller.Create(course, file) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [TestMethod]
        [DataRow(".jpg", DisplayName = "Accepts .jpg")]
        [DataRow(".png", DisplayName = "Accepts .png")]
        [DataRow(".gif", DisplayName = "Accepts .gif")]
        public void Create_Post_ValidFileExtension_RedirectsToIndex(string extension)
        {
            var controller = CreateController(out var context);
            var dept = TestHelper.SeedDepartmentWithInstructor(context);
            var course = new Course { CourseID = 4000, Title = "Valid Image", Credits = 3, DepartmentID = dept.DepartmentID };
            var file = CreateMockFile($"test{extension}", 1024);

            var result = controller.Create(course, file) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        // --- Edit GET ---

        [TestMethod]
        public void Edit_Get_ValidId_ReturnsViewWithCourse()
        {
            var controller = CreateController(out var context);
            var course = SeedCourse(context);

            var result = controller.Edit(course.CourseID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Course;
            Assert.AreEqual("Chemistry", model.Title);
            Assert.IsNotNull(controller.ViewBag.DepartmentID);
        }

        [TestMethod]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var controller = CreateController(out _);

            var result = controller.Edit((int?)null) as StatusCodeResult;

            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Edit_Get_NotFound_ReturnsNotFound()
        {
            var controller = CreateController(out _);

            var result = controller.Edit(9999);

            Assert.IsInstanceOfType(result, typeof(NotFoundResult));
        }

        // --- Edit POST ---

        [TestMethod]
        public void Edit_Post_ValidCourse_RedirectsToIndex()
        {
            var controller = CreateController(out var context);
            var course = SeedCourse(context);
            context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
            var updatedCourse = new Course
            {
                CourseID = course.CourseID,
                Title = "Updated Chemistry",
                Credits = 4,
                DepartmentID = course.DepartmentID
            };

            var result = controller.Edit(updatedCourse, null) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Edit_Post_InvalidFileExtension_ReturnsError()
        {
            var controller = CreateController(out var context);
            var course = SeedCourse(context);
            context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
            var updatedCourse = new Course { CourseID = course.CourseID, Title = "Chemistry", Credits = 3, DepartmentID = course.DepartmentID };
            var file = CreateMockFile("test.doc", 100);

            var result = controller.Edit(updatedCourse, file) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [TestMethod]
        public void Edit_Post_FileTooLarge_ReturnsError()
        {
            var controller = CreateController(out var context);
            var course = SeedCourse(context);
            context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;
            var updatedCourse = new Course { CourseID = course.CourseID, Title = "Chemistry", Credits = 3, DepartmentID = course.DepartmentID };
            var file = CreateMockFile("test.jpg", 6 * 1024 * 1024);

            var result = controller.Edit(updatedCourse, file) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsTrue(controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [TestMethod]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            var controller = CreateController(out var context);
            TestHelper.SeedDepartmentWithInstructor(context);
            controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 1050, DepartmentID = 1 };

            var result = controller.Edit(course, null) as ViewResult;

            Assert.IsNotNull(result);
        }

        // --- Delete ---

        [TestMethod]
        public void Delete_Get_ValidId_ReturnsViewWithCourse()
        {
            var controller = CreateController(out var context);
            var course = SeedCourse(context);

            var result = controller.Delete(course.CourseID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Course;
            Assert.AreEqual("Chemistry", model.Title);
        }

        [TestMethod]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var controller = CreateController(out _);

            var result = controller.Delete(null) as StatusCodeResult;

            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void DeleteConfirmed_ValidId_RemovesCourseAndRedirects()
        {
            var controller = CreateController(out var context);
            var course = SeedCourse(context);

            var result = controller.DeleteConfirmed(course.CourseID) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(0, context.Courses.Count());
        }
    }
}

