using System.Linq;
using System.Net;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class DepartmentsControllerTests
    {
        private DepartmentsController CreateController(out SchoolContext context)
        {
            context = TestHelper.CreateInMemoryContext();
            return new DepartmentsController(context);
        }

        private Department SeedDepartment(SchoolContext context)
        {
            return TestHelper.SeedDepartmentWithInstructor(context);
        }

        // --- Index ---

        [TestMethod]
        public void Index_ReturnsViewWithDepartments()
        {
            var controller = CreateController(out var context);
            SeedDepartment(context);

            var result = controller.Index() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<Department>;
            Assert.AreEqual(1, model.Count);
        }

        [TestMethod]
        public void Index_EmptyDatabase_ReturnsEmptyList()
        {
            var controller = CreateController(out _);

            var result = controller.Index() as ViewResult;

            var model = result.Model as List<Department>;
            Assert.AreEqual(0, model.Count);
        }

        // --- Details ---

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            var controller = CreateController(out var context);
            var dept = SeedDepartment(context);

            var result = controller.Details(dept.DepartmentID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Department;
            Assert.AreEqual("Engineering", model.Name);
        }

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var controller = CreateController(out _);

            var result = controller.Details(null) as StatusCodeResult;

            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Details_NotFound_ReturnsNotFound()
        {
            var controller = CreateController(out _);

            var result = controller.Details(999);

            Assert.IsInstanceOfType(result, typeof(NotFoundResult));
        }

        // --- Create GET ---

        [TestMethod]
        public void Create_Get_ReturnsViewWithInstructorDropdown()
        {
            var controller = CreateController(out var context);
            context.Instructors.Add(new Instructor { FirstMidName = "Kim", LastName = "Abercrombie", HireDate = DateTime.Parse("1995-03-11") });
            context.SaveChanges();

            var result = controller.Create() as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsNotNull(controller.ViewBag.InstructorID);
        }

        // --- Create POST ---

        [TestMethod]
        public void Create_Post_ValidDepartment_RedirectsToIndex()
