using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class InstructorsControllerTests
    {
        private InstructorsController CreateController(out SchoolContext context)
        {
            context = TestHelper.CreateInMemoryContext();
            return new InstructorsController(context);
        }

        private Instructor SeedInstructor(SchoolContext context, string firstName = "Kim", string lastName = "Abercrombie")
        {
            var instructor = new Instructor
            {
                FirstMidName = firstName,
                LastName = lastName,
                HireDate = DateTime.Parse("1995-03-11"),
                CourseAssignments = new List<CourseAssignment>()
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();
            return instructor;
        }

        private (Instructor instructor, Course course) SeedInstructorWithCourse(SchoolContext context)
        {
            var instructor = SeedInstructor(context);
            var dept = new Department
            {
                Name = "Engineering",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01"),
                InstructorID = instructor.ID
            };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = dept.DepartmentID,
                Enrollments = new List<Enrollment>()
            };
            context.Courses.Add(course);
            context.SaveChanges();

            context.CourseAssignments.Add(new CourseAssignment { InstructorID = instructor.ID, CourseID = course.CourseID });
            context.SaveChanges();

            return (instructor, course);
        }

        // --- Index ---

        [TestMethod]
        public void Index_NoSelection_ReturnsAllInstructors()
        {
            var controller = CreateController(out var context);
            SeedInstructor(context, "Kim", "Abercrombie");
            SeedInstructor(context, "Fadi", "Fakhouri");

            var result = controller.Index(null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Instructors.Count());
        }

        [TestMethod]
        public void Index_WithInstructorId_ShowsCourses()
        {
            var controller = CreateController(out var context);
            var (instructor, _) = SeedInstructorWithCourse(context);

            var result = controller.Index(instructor.ID, null) as ViewResult;

            var model = result.Model as InstructorIndexData;
            Assert.IsNotNull(model.Courses);
            Assert.AreEqual(1, model.Courses.Count());
        }

        [TestMethod]
        public void Index_WithInstructorId_SetsViewBagInstructorID()
        {
            var controller = CreateController(out var context);
            var (instructor, _) = SeedInstructorWithCourse(context);

            controller.Index(instructor.ID, null);

            Assert.AreEqual(instructor.ID, controller.ViewBag.InstructorID);
        }

        [TestMethod]
        public void Index_InstructorsOrderedByLastName()
        {
            var controller = CreateController(out var context);
            SeedInstructor(context, "Zara", "Zed");
            SeedInstructor(context, "Alice", "Adams");

            var result = controller.Index(null, null) as ViewResult;

            var model = result.Model as InstructorIndexData;
            Assert.AreEqual("Adams", model.Instructors.First().LastName);
            Assert.AreEqual("Zed", model.Instructors.Last().LastName);
        }

        // --- Details ---

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            var controller = CreateController(out var context);
            var instructor = SeedInstructor(context);

            var result = controller.Details(instructor.ID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Instructor;
            Assert.AreEqual("Abercrombie", model.LastName);
        }

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            var controller = CreateController(out _);

            var result = controller.Details(null) as StatusCodeResult;

            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Details_NotFound_ReturnsNotFound()
