namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class NotificationsControllerTests
    {
        [TestInitialize]
        public void Setup()
        {
            // Drain the static notification queue to avoid cross-test interference
            var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }
            service.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            using var context = TestHelper.CreateInMemoryContext();
            var controller = new NotificationsController(context);

            var result = controller.Index();

            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }

        [TestMethod]
        public void GetNotifications_WhenEmpty_ReturnsJsonResult()
        {
            using var context = TestHelper.CreateInMemoryContext();
            var controller = new NotificationsController(context);

            var result = controller.GetNotifications();

            Assert.IsNotNull(result);
            Assert.IsInstanceOfType(result, typeof(JsonResult));
        }

        [TestMethod]
        public void GetNotifications_WithQueuedItems_ReturnsNotifications()
        {
            using var context = TestHelper.CreateInMemoryContext();
            var service = new NotificationService();
            service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
            service.Dispose();

            var controller = new NotificationsController(context);

            var result = controller.GetNotifications();

            Assert.IsNotNull(result);
            Assert.IsInstanceOfType(result, typeof(JsonResult));
        }

        [TestMethod]
        public void MarkAsRead_ReturnsJsonResult()
        {
            using var context = TestHelper.CreateInMemoryContext();
            var controller = new NotificationsController(context);

            var result = controller.MarkAsRead(1);

            Assert.IsNotNull(result);
            Assert.IsInstanceOfType(result, typeof(JsonResult));
        }
    }
}
