using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.VisualStudio.TestTools.UnitTesting;
using System;
using System.Linq;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class DbInitializerTests
    {
        [TestMethod]
        public void Initialize_EmptyDatabase_SeedsStudents()
        {
            using var context = TestHelper.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.AreEqual(8, context.Students.Count());
        }

        [TestMethod]
        public void Initialize_EmptyDatabase_SeedsInstructors()
        {
            using var context = TestHelper.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.AreEqual(5, context.Instructors.Count());
        }

        [TestMethod]
        public void Initialize_EmptyDatabase_SeedsDepartments()
        {
            using var context = TestHelper.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.AreEqual(4, context.Departments.Count());
        }

        [TestMethod]
        public void Initialize_EmptyDatabase_SeedsCourses()
        {
            using var context = TestHelper.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.AreEqual(7, context.Courses.Count());
        }

        [TestMethod]
        public void Initialize_EmptyDatabase_SeedsEnrollments()
        {
            using var context = TestHelper.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.AreEqual(11, context.Enrollments.Count());
        }

        [TestMethod]
        public void Initialize_EmptyDatabase_SeedsOfficeAssignments()
        {
            using var context = TestHelper.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.AreEqual(3, context.OfficeAssignments.Count());
        }

        [TestMethod]
        public void Initialize_EmptyDatabase_SeedsCourseAssignments()
        {
            using var context = TestHelper.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.AreEqual(8, context.CourseAssignments.Count());
        }

        [TestMethod]
        public void Initialize_ExistingStudents_DoesNotReseed()
        {
            using var context = TestHelper.CreateInMemoryContext();
            context.Students.Add(new Student
            {
                FirstMidName = "Existing",
                LastName = "Student",
                EnrollmentDate = DateTime.Today
            });
            context.SaveChanges();

            DbInitializer.Initialize(context);

            Assert.AreEqual(1, context.Students.Count());
        }

        [TestMethod]
        public void Initialize_SeedsCorrectStudentNames()
        {
            using var context = TestHelper.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            var studentNames = context.Students.Select(s => s.LastName).OrderBy(n => n).ToList();
            Assert.IsTrue(studentNames.Contains("Alexander"));
            Assert.IsTrue(studentNames.Contains("Alonso"));
            Assert.IsTrue(studentNames.Contains("Olivetto"));
        }

        [TestMethod]
        public void Initialize_SeedsCorrectDepartmentNames()
        {
            using var context = TestHelper.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            var deptNames = context.Departments.Select(d => d.Name).OrderBy(n => n).ToList();
            CollectionAssert.AreEqual(
                new[] { "Economics", "Engineering", "English", "Mathematics" },
                deptNames);
        }
    }
}

